def handle_single_publish(event: Dict[str, Any]) -> Dict[str, Any]:
    """Handle single message publication to SNS."""
    
    topic_arn = event.get('topic_arn')
    if not topic_arn:
        topic_arn = os.environ.get('DEFAULT_TOPIC_ARN')
    
    if not topic_arn:
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'topic_arn is required'
            })
        }
    
    message = event.get('message')
    if not message:
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'message is required'
            })
        }
    
    notification_type = event.get('notification_type', 'all')
    
    message_payload = prepare_message(message, notification_type)
    
    publish_params = {
        'TopicArn': topic_arn,
        'Message': message_payload
    }
    
    subject = event.get('subject')
    if subject:
        publish_params['Subject'] = subject[:100]
    
    message_attributes = event.get('message_attributes', {})
    if message_attributes:
        publish_params['MessageAttributes'] = format_message_attributes(message_attributes)
    
    message_structure = event.get('message_structure')
    if message_structure:
        publish_params['MessageStructure'] = message_structure
    
    message_deduplication_id = event.get('message_deduplication_id')
    if message_deduplication_id:
        publish_params['MessageDeduplicationId'] = message_deduplication_id
    
    message_group_id = event.get('message_group_id')
    if message_group_id:
        publish_params['MessageGroupId'] = message_group_id
    
    response = sns_client.publish(**publish_params)
    
    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'Message published successfully',
            'message_id': response['MessageId'],
            'topic_arn': topic_arn,
            'timestamp': datetime.utcnow().isoformat()
        })
    }


def handle_batch_publish(event: Dict[str, Any]) -> Dict[str, Any]:
    """Handle batch message publication to SNS."""
    
    topic_arn = event.get('topic_arn')
    if not topic_arn:
        topic_arn = os.environ.get('DEFAULT_TOPIC_ARN')
    
    if not topic_arn:
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'topic_arn is required for batch publishing'
            })
        }
    
    batch_messages = event.get('batch_messages', [])
    if not batch_messages:
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'batch_messages is required and cannot be empty'
            })
        }
    
    results = []
    failed = []
    
    for idx, msg_data in enumerate(batch_messages):
        try:
            message = msg_data.get('message')
            if not message:
                failed.append({
                    'index': idx,
                    'error': 'message is required'
                })
                continue
            
            notification_type = msg_data.get('notification_type', 'all')
            message_payload = prepare_message(message, notification_type)
            
            publish_params = {
                'TopicArn': topic_arn,
                'Message': message_payload
            }
            
            subject = msg_data.get('subject')
            if subject:
                publish_params['Subject'] = subject[:100]
            
            message_attributes = msg_data.get('message_attributes', {})
            if message_attributes:
                publish_params['MessageAttributes'] = format_message_attributes(message_attributes)
            
            response = sns_client.publish(**publish_params)
            
            results.append({
                'index': idx,
                'message_id': response['MessageId'],
                'status': 'success'
            })
            
        except Exception as e:
            failed.append({
                'index': idx,
                'error': str(e)
            })
    
    return {
        'statusCode': 200 if not failed else 207,
        'body': json.dumps({
            'message': 'Batch publish completed',
            'total': len(batch_messages),
            'successful': len(results),
            'failed': len(failed),
            'results': results,
            'failures': failed,
            'timestamp': datetime.utcnow().isoformat()
        })
    }


def prepare_message(message: Any, notification_type: str) -> str:
    """Prepare message based on notification type."""
    
    if notification_type == 'all' or notification_type == 'default':
        if isinstance(message, dict):
            return json.dumps(message)
        return str(message)
    
    if notification_type in ['email', 'sms', 'application', 'lambda', 'sqs', 'http', 'https']:
        if isinstance(message, dict):
            structured_message = {
                'default': message.get('default', json.dumps(message))
            }
            
            if notification_type == 'email' and 'email' in message:
                structured_message['email'] = message['email']
            elif notification_type == 'sms' and 'sms' in message:
                structured_message['sms'] = message['sms']
            elif notification_type == 'application' and 'application' in message:
                structured_message['GCM'] = message.get('GCM', message.get('application', ''))
                structured_message['APNS'] = message.get('APNS', message.get('application', ''))
            elif notification_type == 'lambda' and 'lambda' in message:
                structured_message['lambda'] = message['lambda']
            elif notification_type == 'sqs' and 'sqs' in message:
                structured_message['sqs'] = message['sqs']
            elif notification_type in ['http', 'https']:
                protocol_key = notification_type
                if protocol_key in message:
                    structured_message[protocol_key] = message[protocol_key]
            
            return json.dumps(structured_message)
        else:
            return str(message)
    
    if isinstance(message, dict):
        return json.dumps(message)
    return str(message)


def format_message_attributes(attributes: Dict[str, Any]) -> Dict[str, Dict[str, str]]:
    """Format message attributes for SNS."""
    
    formatted_attributes = {}
    
    for key, value in attributes.items():
        if isinstance(value, dict) and 'DataType' in value:
            formatted_attributes[key] = value
        else:
            if isinstance(value, (int, float)):
                formatted_attributes[key] = {
                    'DataType': 'Number',
                    'StringValue': str(value)
                }
            elif isinstance(value, str):
                formatted_attributes[key] = {
                    'DataType': 'String',
                    'StringValue': value
                }
            elif isinstance(value, list):
                formatted_attributes[key] = {
                    'DataType': 'String.Array',
                    'StringValue': json.dumps(value)
                }
            else:
                formatted_attributes[key] = {
                    'DataType': 'String',
                    'StringValue': str(value)
                }
    
    return formatted_attributes


def publish_notification(topic_arn: str, message: str, subject: Optional[str] = None,
                         attributes: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Helper function to publish a notification."""
    
    publish_params = {
        'TopicArn': topic_arn,
        'Message': message
    }
    
    if subject:
        publish_params['Subject'] = subject[:100]
    
    if attributes:
        publish_params['MessageAttributes'] = format_message_attributes(attributes)
    
    return sns_client.publish(**publish_params)


def publish_structured_notification(topic_arn: str, messages: Dict[str, str],
                                    subject: Optional[str] = None) -> Dict[str, Any]:
    """Publish structured notification with protocol-specific messages."""
    
    publish_params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(messages),
        'MessageStructure': 'json'
    }
    
    if subject:
        publish_params['Subject'] = subject[:100]
    
    return sns_client.publish(**publish_params)


def publish_alert(topic_arn: str, alert_type: str, alert_message: str,
                  severity: str = 'INFO', metadata: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Publish an alert notification with standardized format."""
    
    alert_payload = {
        'alert_type': alert_type,
        'message': alert_message,
        'severity': severity,
        'timestamp': datetime.utcnow().isoformat()
    }
    
    if metadata:
        alert_payload['metadata'] = metadata
    
    message_attributes = {
        'alert_type': {
            'DataType': 'String',
            'StringValue': alert_type
        },
        'severity': {
            'DataType': 'String',
            'StringValue': severity
        }
    }
    
    return sns_client.publish(
        TopicArn=topic_arn,
        Message=json.dumps(alert_payload),
        Subject=f'{severity}: {alert_type}',
        MessageAttributes=message_attributes
    )